43				filename: workerPath,
44				minThreads: 1,
45				maxThreads: Math.max(1, cpuCount - 1),
46				idleTimeout: 30000,
47				...(isDevelopment && {
48					execArgv: [
49						'--require',
50						'ts-node/register',
51						'--require',
52						'tsconfig-paths/register',
53					],
54				}),
55			});
56	
57			this.logger.log(
58				`Color match worker pool initialized: workerPath=${workerPath}, minThreads=1, maxThreads=${Math.max(1, cpuCount - 1)}`,
59			);
60		}
