69		async findClosestColorId({
70			color,
71			palette,
72		}: {
73			color: IStyleColorBase | null;
74			palette: IProductColor[];
75		}): Promise<number> {
76			if (!color || !palette.some((item) => item.rbgs?.length)) {
77				this.logger.warn(
78					'[findClosestColorId]: No color or palette provided, defaulting to color ID 0',
79				);
80				return 0;
81			}
82	
83			const referenceColor = palette.find((item) => item.name === color.color_name);
84	
85			if (referenceColor) {
86				this.logger.debug(
87					`[findClosestColorId]: Exact color match found for "${color.color_name}", using color ID ${referenceColor.id}`,
88				);
89				return referenceColor.id;
90			}
91	
92			const selectedColorRGB = color.color_rgb;
93	
94			if (!selectedColorRGB || !palette.length) {
95				this.logger.warn(
96					'[findClosestColorId]: No selected color RGB or empty palette, defaulting to color ID 0',
97				);
98				return 0;
99			}
100	
101			const colorsHash = getColorRGBToIdHash({ colors: palette });
102	
103			const paletteColors = palette.reduce<{ R: number; G: number; B: number }[]>(
104				(acc, color) => {
105					if (color.rbgs?.[0]) {
106						acc.push(color.rbgs[0]);
107					}
108					return acc;
109				},
110				[],
111			);
112	
113			const closestColorId = (await this.pool.run({
114				selectedColorRGB: convertStringToRGB({ str: selectedColorRGB }),
115				paletteColors,
116				colorsHash,
117			})) as number;
118	
119			this.logger.debug(
120				`[findClosestColorId]: Closest color to "${color.color_name}" (RGB: ${selectedColorRGB}) is color ID ${closestColorId}. colorsHash: ${JSON.stringify(colorsHash)}, paletteColors: ${JSON.stringify(paletteColors)}`,
121			);
122	
123			return closestColorId;
124		}
125	}
